import{u as e}from"./index.95f2040e.js";import{_ as n,c as a,o as i,f as t}from"./entry.79f37cee.js";import"./vue.f36acd1f.494dcfe6.js";const s={class:"row"},r=t('<div class="col-xs-12 col-md-offset-1 col-lg-offset-2 col-lg-9 col-md-10" data-v-2c3125af><h2 class="z-100" data-v-2c3125af> Mein Angebot </h2><h1 class="z-100" data-v-2c3125af> Agile Teamentwicklung </h1><h3 class="z-100" data-v-2c3125af>Mit innovativen Methoden und agilen Impulsen die Zukunft eurer Zusammenarbeit gestalten</h3><p class="z-100" data-v-2c3125af>Ihr wollt als Team etwas bewegen und gemeinsam weiter kommen? Teamentwicklung ist der Schlüssel, um die Kommunikation, das Vertrauen und den Zusammenhalt im Team zu stärken und die Grundlage für effektive Zusammenarbeit zu schaffen. Mit individuell zugeschnittenem Ansatz unterstütze ich euch dabei, nachhaltige Veränderungen zu bewirken.</p><p class="z-100" data-v-2c3125af>Kreative Methoden, agile Impulse und ein starker Fokus auf Reflexion und Selbsthilfe prägen meine Arbeit. So werden die im Team vorhandenen Ressourcen und Kompetenzen für alle Beteiligten sichtbar. Ich unterstütze dabei, diese bewusster einzusetzen und die Dialog- und Arbeitsfähigkeit nachhaltig zu fördern. Dabei setze ich auf partizipative Methoden. Denn ich bin überzeugt: Die Vielfalt der Perspektiven und die aktive Beteiligung aller Teammitglieder führen zu kreativen und guten Lösungen.</p><p class="z-100" data-v-2c3125af>Ich arbeite regelmäßig mit Remote-Teams zusammen und führe alle Teamentwicklungsprozesse auch online durch.</p><h2 class="z-100" data-v-2c3125af>Meine Leistungen</h2><h3 class="z-100" data-v-2c3125af>Agiles Arbeiten im Team</h3><p class="z-100" data-v-2c3125af>Teams in agilen Kontexten, die verstärkt auf Selbstorganisation setzen wollen, stehen vor besonderen Herausforderungen. Denn die bloße Einführung agiler Methoden oder Frameworks reicht oft nicht aus. Oftmals bleibt unklar, was Agilität und Selbstorganisation im Kern bedeuten und wie diese Prinzipien im Alltag konkret umgesetzt werden können.</p><p class="z-100" data-v-2c3125af>Die Dezentralisierung von klassischen Führungsaufgaben erfordert mehr Struktur und klare Regeln, um effektiv und produktiv zusammenarbeiten zu können. Ich unterstütze euch dabei einen guten Rahmen für eure Zusammenarbeit zu schaffen</p><p class="z-100" data-v-2c3125af>Gemeinsam können wir folgende Themen angehen:</p><p class="z-100" data-v-2c3125af><b data-v-2c3125af>Agile Methoden in der Praxis: </b>Ihr habt agile Methoden eingeführt, aber die Umsetzung hapert und stößt auf Unzufriedenheit? Wir analysieren die Herausforderungen und entwickeln gemeinsam praktikable Lösungen.</p><p class="z-100" data-v-2c3125af><b data-v-2c3125af>Gemeinsames Verständnis schaffen: </b>Euch fehlt ein klares Bild davon, was Agilität und Selbstorganisation für das Team bedeuten? Wir erarbeiten ein gemeinsames Verständnis und Leitbild.</p><p class="z-100" data-v-2c3125af><b data-v-2c3125af>Agiler Einstieg: </b>Ihr möchtet agil arbeiten, wisst aber nicht, wo ihr beginnen sollt und was für euren Kontext sinnvoll ist? Ich begleite euch bei der Einführung agiler Prinzipien und Praktiken.</p><p class="z-100" data-v-2c3125af><b data-v-2c3125af>Verantwortung übernehmen: </b>Ihr setzt auf Selbstorganisation und geteilte Führung, doch im Alltag wird wenig Verantwortung übernommen? Die Erarbeitung und Verteilung klarer Rollen und Aufgaben stärkt die Selbstorganisation im Team und führt dazu, dass Verantwortung übernommen werden kann.</p><p class="z-100" data-v-2c3125af><b data-v-2c3125af>Gemeinsam Entscheidungen treffen: </b> Ihr wollt Entscheidungen gemeinsam treffen, merkt aber, dass dies zu langwierigen und nervenaufreibenden Prozessen führt? Wir schauen uns an, wie ihr alle einbeziehen könnt und dennoch vorankommt.</p><h3 class="z-100" data-v-2c3125af>Team Kick-Off-Workshops</h3><p class="z-100" data-v-2c3125af>Für neu zusammengesetzte Teams ist es zentral eine gute Grundlage für die gemeinsame Zusammenarbeit zu schaffen. Im Rahmen eines Team Kick-Offs lernen sich alle Team-Mitglieder besser kennen, wir sprechen über eure gemeinsamen Ziele, klären Rollen im Team sowie die Spielregeln eurer Zusammenarbeit.</p><h3 class="z-100" data-v-2c3125af>Teamcoaching</h3><p class="z-100" data-v-2c3125af>Bestehende Teams, die ihre Zusammenarbeit verbessern möchten oder Lösungen für konkrete Herausforderungen finden wollen, begleite ich als Teamcoach. Mögliche Anlässe für ein Teamcoaching sind:</p><ul class="z-100" data-v-2c3125af><li data-v-2c3125af>Verbesserung von Zusammenarbeit und Kommunikation</li><li data-v-2c3125af>Klärung von Rollen im Team</li><li data-v-2c3125af>Optimierung von Prozessen</li><li data-v-2c3125af>Verbesserungen der Zusammenarbeit in remote oder hybriden Teams</li><li data-v-2c3125af>Klärung von Spannungen und Konflikten</li></ul></div>',1),l=[r],u={name:"Teamcoaching"},d=Object.assign(u,{setup(c){return e({title:"Teamentwicklung",ogTitle:"Teamentwicklung",ogDescription:"Als Teamentwicklerin unterstütze ich Teams dabei, die Zusammenarbeit und Kommunikation innerhalb des Teams zu verbessern, gemeinsame Ziele zu definieren und zu erreichen.",description:"Als Teamentwicklerin unterstütze ich Teams dabei, die Zusammenarbeit und Kommunikation innerhalb des Teams zu verbessern, gemeinsame Ziele zu definieren und zu erreichen."}),(m,o)=>(i(),a("div",s,l))}}),b=n(d,[["__scopeId","data-v-2c3125af"]]);export{b as default};
